questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Component values (for t > 0 parallel RLC) ===== */
R_val:  if set=1 then 50   else if set=2 then 20   else 50;
L_mH:   if set=1 then 160  else if set=2 then 1000 else 250;
L_val:  L_mH/1000;
C_uF:   if set=1 then 25   else if set=2 then 100  else 25;
C_val:  C_uF*1e-6;

/* ===== Pre-switch initial conditions ===== */
V0_val: if set=1 then 100  else if set=2 then 50   else 75;
I0_val: if set=1 then 5    else if set=2 then 2    else 3;

/* ===== Pre-switch circuit display values ===== */
Is_val:  I0_val;
Ra_val:  if set=1 then 250 else if set=2 then 400 else 300;
Rb_val:  if set=1 then 75  else if set=2 then 150 else 80;
Vdc_val: V0_val;

/* ===== Damping parameters (parallel RLC) ===== */
ta_alpha:  float(1/(2*R_val*C_val));
ta_omega0: float(1/sqrt(L_val*C_val));
disc: float(ta_alpha^2 - ta_omega0^2);

/* ===== Regime classification ===== */
ta_regime: if abs(ta_alpha-ta_omega0) < 1.0 then 3
           else if disc > 0 then 1
           else 2;
regime_name: if ta_regime=1 then "overdamped"
             else if ta_regime=2 then "underdamped"
             else "critically damped";

/* ===== Damped frequency / root separation ===== */
ta_omegad: float(sqrt(abs(disc)));

/* ===== Characteristic roots ===== */
s1_r: if ta_regime=1 then float(-ta_alpha+sqrt(disc)) else float(-ta_alpha);
s2_r: if ta_regime=1 then float(-ta_alpha-sqrt(disc)) else float(-ta_alpha);

/* ===== dv/dt(0+) ===== */
dvdt0: float(-(1/C_val)*(V0_val/R_val + I0_val));

/* ===== Coefficients ===== */
ta_A1: if ta_regime=1 then float((dvdt0 - s2_r*V0_val)/(s1_r - s2_r)) else 0;
ta_A2: if ta_regime=1 then float(V0_val - ta_A1) else 0;
ta_B1: if ta_regime=2 then float(V0_val) else 0;
ta_B2: if ta_regime=2 then float((dvdt0 + ta_alpha*ta_B1)/ta_omegad) else 0;
ta_D2: if ta_regime=3 then float(V0_val) else 0;
ta_D1: if ta_regime=3 then float(dvdt0 + ta_alpha*ta_D2) else 0;

/* ===== v_o(t) complete ===== */
ta_vo: if ta_regime=1 then ta_A1*exp(s1_r*t) + ta_A2*exp(s2_r*t)
       else if ta_regime=2 then exp(-ta_alpha*t)*(ta_B1*cos(ta_omegad*t)+ta_B2*sin(ta_omegad*t))
       else (ta_D1*t+ta_D2)*exp(-ta_alpha*t);

/* ===== Teacher answers ===== */
ta1: float(V0_val);
ta2: float(I0_val);
ta3: ta_alpha;
ta4: ta_omega0;
ta5: [[1, is(ta_regime=1), "Overdamped"], [2, is(ta_regime=2), "Underdamped"], [3, is(ta_regime=3), "Critically damped"]];
ta6: if ta_regime=1 then A1*exp(s1_r*t) + A2*exp(s2_r*t)
     else if ta_regime=2 then exp(-ta_alpha*t)*(B1*cos(ta_omegad*t)+B2*sin(ta_omegad*t))
     else (D1*t+D2)*exp(-ta_alpha*t);
ta7: ta_vo;
ta8: 0;

/* ===== Numerical sampling ===== */
t_test1: 1.0e-4;
t_test2: 5.0e-4;
t_test3: 1.0e-3;
ta7_at_t1: float(subst(t=t_test1, ta7));
ta7_at_t2: float(subst(t=t_test2, ta7));
ta7_at_t3: float(subst(t=t_test3, ta7));

feedbackvariables.text:
sa7_at_t1: float(subst(t=t_test1, ans7));
sa7_at_t2: float(subst(t=t_test2, ans7));
sa7_at_t3: float(subst(t=t_test3, ans7));
rerr7_1: if abs(ta7_at_t1) > 1.0e-10 then abs((sa7_at_t1 - ta7_at_t1)/ta7_at_t1) else abs(sa7_at_t1 - ta7_at_t1);
rerr7_2: if abs(ta7_at_t2) > 1.0e-10 then abs((sa7_at_t2 - ta7_at_t2)/ta7_at_t2) else abs(sa7_at_t2 - ta7_at_t2);
rerr7_3: if abs(ta7_at_t3) > 1.0e-10 then abs((sa7_at_t3 - ta7_at_t3)/ta7_at_t3) else abs(sa7_at_t3 - ta7_at_t3);
vo_num_ok: if rerr7_1 < 0.05 and rerr7_2 < 0.05 and rerr7_3 < 0.05 then true else false;
